import React from 'react';

const Home = () => {
  // صرف لاجسٹک اور ٹرانسپورٹ والی تصاویر
  const logisticsServices = [
    { name: 'Cargo Flight', img: '/butans/cargo-flay.jpg' },
    { name: 'Ship Cargo', img: '/butans/ship-cargo.jpg' },
    { name: 'Parcel Delivery', img: '/butans/parcel-delivry.jpg' },
    { name: 'Home Shifting', img: '/butans/home_shifting.jpg' },
    { name: 'Cargo Train', img: '/butans/cargo-train.jpg' },
    { name: 'Logistics', img: '/butans/lOKgestics.jpg' }
  ];

  return (
    <div style={{ padding: '20px', backgroundColor: '#f4f4f4', minHeight: '100vh' }}>
      <h2 style={{ textAlign: 'center' }}>Logistics Services</h2>
      <div style={{ 
        display: 'grid', 
        gridTemplateColumns: 'repeat(2, 1fr)', 
        gap: '15px' 
      }}>
        {logisticsServices.map((service, index) => (
          <div key={index} style={{ 
            background: '#fff', 
            padding: '10px', 
            borderRadius: '10px', 
            textAlign: 'center',
            boxShadow: '0 2px 5px rgba(0,0,0,0.1)'
          }}>
            <img src={service.img} alt={service.name} style={{ width: '80px', height: '80px', objectFit: 'cover' }} />
            <p style={{ fontSize: '14px', fontWeight: 'bold' }}>{service.name}</p>
          </div>
        ))}
      </div>
    </div>
  );
};
export default Home;
